"""Outbound auth CLI for GreenNode AgentBase.

Manages static (API key), delegated (delegated API key), and OAuth2 outbound auth
providers. All data is collected via interactive prompts; execution runs only after
every required field is entered; empty or 'q' at any step cancels gently.
"""

import asyncio
import logging
from typing import Any, Optional

import click
from rich.console import Console
from rich.prompt import Prompt
from rich.table import Table

from ..core.logging import configure_logger
from ..core import run_async_with_cleanup
from ..exceptions import GreenNodeConfigurationError, GreenNodeRequestError
from ..identity.models import (
    CreateApikeyProviderRequest,
    CreateDelegatedApiKeyProviderRequest,
    CreateOauth2ProviderRequest,
    GetDelegatedApiKeyRequest,
    GetM2mTokenRequest,
    ThreeLoTokenRequest,
    UpdateApikeyProviderRequest,
    UpdateOauth2ProviderRequest,
)
from . import CONTEXT_SETTINGS

logger = logging.getLogger("greennode_agentbase.cli.outbound_auth")
configure_logger(logger)

console = Console()

# Sentinel for user cancel (empty or q/quit/cancel)
class _Cancelled:
    pass

CANCELLED = _Cancelled()


def _is_cancel(value: str) -> bool:
    if value is None or (isinstance(value, str) and value.strip() == ""):
        return True
    return value.strip().lower() in ("q", "quit", "cancel")


def prompt_field(
    label: str,
    default: Optional[str] = None,
    password: bool = False,
) -> Any:
    """Prompt for a value. Returns CANCELLED if user cancels, else the string value.

    Treats empty string or 'q'/'quit'/'cancel' as cancel.
    """
    if default is not None:
        prompt_label = f"{label} [default: {default}]"
    else:
        prompt_label = label
    raw = Prompt.ask(prompt_label, password=password, default=default or "")
    if _is_cancel(raw):
        return CANCELLED
    return raw.strip() if raw else (default or "")


def prompt_optional(label: str, default: Optional[str] = None) -> Any:
    """Prompt for an optional value. Empty = skip (return None). q/quit/cancel = CANCELLED."""
    raw = Prompt.ask(label, default=default or "")
    if raw is None:
        return None
    s = (raw or "").strip()
    if s.lower() in ("q", "quit", "cancel"):
        return CANCELLED
    return s if s else None


def prompt_if_missing(value: Optional[str], label: str, default: Optional[str] = None) -> Any:
    """If value is None/empty, prompt user. Returns CANCELLED or the value."""
    if value is not None and str(value).strip():
        return value
    return prompt_field(label, default=default)


def prompt_scopes() -> Any:
    """Prompt for scopes (comma-separated). Returns CANCELLED or list of non-empty scope strings."""
    raw = Prompt.ask("Scopes (comma-separated)", default="")
    if _is_cancel(raw):
        return CANCELLED
    scopes = [s.strip() for s in raw.split(",") if s.strip()]
    if not scopes:
        return CANCELLED
    return scopes


def _cancel_exit() -> None:
    console.print("Cancelled.")
    raise SystemExit(0)


def _ensure_not_cancelled(value: Any, _name: str = "") -> None:
    if value is CANCELLED:
        _cancel_exit()


def _run_async(client, coro):
    return run_async_with_cleanup(client, coro)


def _get_client():
    from .identity import get_identity_client
    return get_identity_client()


# ---------------------------------------------------------------------------
# Outbound auth group
# ---------------------------------------------------------------------------

@click.group(name="outbound-auth", context_settings=CONTEXT_SETTINGS)
def outbound_auth_group() -> None:
    """Manage outbound auth: static (API key), delegated, and OAuth2 providers.

    Prompt for each field; leave empty or type 'q' to cancel at any step.
    """
    pass


# ---------------------------------------------------------------------------
# Static (API key provider)
# ---------------------------------------------------------------------------

@outbound_auth_group.group(name="static")
def static_group() -> None:
    """API key (static) outbound auth providers."""
    pass


@static_group.command(name="create")
def static_create() -> None:
    """Create an API key provider.

    Prompts: name, apikey.

    Examples:
        greennode identity outbound-auth static create
    """
    name = prompt_field("Provider name")
    _ensure_not_cancelled(name, "name")
    apikey = prompt_field("API key", password=True)
    _ensure_not_cancelled(apikey, "apikey")
    try:
        client = _get_client()
        result = _run_async(
            client,
            client.create_api_key_provider_async(
                request=CreateApikeyProviderRequest(name=name, apikey=apikey)
            )
        )
        console.print(f"[green]Created API key provider: {getattr(result, 'name', name)}[/green]")
    except (GreenNodeConfigurationError, GreenNodeRequestError) as e:
        console.print(f"[red]Error: {e}[/red]")
        raise click.Abort()


@static_group.command(name="list")
def static_list() -> None:
    """List API key providers.

    Prompts: page, size (defaults 1, 10).

    Examples:
        greennode identity outbound-auth static list
    """
    page_s = prompt_field("Page", default="1")
    _ensure_not_cancelled(page_s, "page")
    size_s = prompt_field("Size", default="10")
    _ensure_not_cancelled(size_s, "size")
    try:
        page = int(page_s)
        size = int(size_s)
    except ValueError:
        console.print("[red]Error: page and size must be integers.[/red]")
        raise click.Abort()
    try:
        client = _get_client()
        try:
            method = getattr(client, "list_api_key_providers_async")
        except AttributeError:
            console.print("[yellow]List not available for this provider type.[/yellow]")
            return
        result = _run_async(client, method(page=page - 1, size=size))
    except (GreenNodeConfigurationError, GreenNodeRequestError) as e:
        console.print(f"[red]Error: {e}[/red]")
        raise click.Abort()
    content = getattr(result, "content", None) or []
    if not content:
        console.print("[dim]No providers returned.[/dim]")
        return
    table = Table(title="API key providers")
    table.add_column("Name", style="cyan")
    table.add_column("Id", style="dim")
    table.add_column("Status", style="dim")
    for item in content:
        table.add_row(
            getattr(item, "name", "") or "",
            getattr(item, "id", "") or "",
            str(getattr(item, "status", "")),
        )
    console.print(table)


