@oauth2_group.command(name="3lo-token")
def oauth2_3lo_token() -> None:
    """Get 3LO OAuth2 token. Prompts: provider_name, agent_identity_name, agent_user_id, scopes, return_url; optional: session_id, custom_state, force_authentication."""
    provider_name = prompt_field("Provider name")
    _ensure_not_cancelled(provider_name, "provider_name")
    agent_identity_name = prompt_field("Agent identity name")
    _ensure_not_cancelled(agent_identity_name, "agent_identity_name")
    agent_user_id = prompt_field("Agent user ID")
    _ensure_not_cancelled(agent_user_id, "agent_user_id")
    scopes = prompt_scopes()
    _ensure_not_cancelled(scopes, "scopes")
    return_url = prompt_optional("Return URL (optional)")
    if return_url is CANCELLED:
        _cancel_exit()
    session_id = prompt_optional("Session ID (optional, UUID)")
    if session_id is CANCELLED:
        _cancel_exit()
    custom_state = prompt_optional("Custom state (optional)")
    if custom_state is CANCELLED:
        _cancel_exit()
    force_s = prompt_optional("Force authentication (optional, true/false)")
    if force_s is CANCELLED:
        _cancel_exit()
    force_authentication = None
    if force_s:
        force_authentication = force_s.strip().lower() in ("true", "1", "yes")
    try:
        client = _get_client()
        req = ThreeLoTokenRequest(
            agent_user_id=agent_user_id,
            scopes=scopes,
            return_url=return_url,
            session_id=session_id,
            custom_state=custom_state,
            force_authentication=force_authentication,
        )
        result = _run_async(
            client,
            client.get_3lo_token_async(
                provider_name=provider_name,
                agent_identity_name=agent_identity_name,
                request=req,
            )
        )
        authorization_url = getattr(result, "authorization_url", None)
        access_token = getattr(result, "access_token", None)
        if authorization_url:
            console.print(f"[green]Authorization URL: {authorization_url}[/green]")
        if access_token:
            console.print(f"[green]Access token: {access_token}[/green]")
        if not authorization_url and not access_token:
            console.print(result)
    except (GreenNodeConfigurationError, GreenNodeRequestError) as e:
        console.print(f"[red]Error: {e}[/red]")
        raise click.Abort()


